// Cole aqui o conteudo do seu codec JavaScript.
// Use templates/codecs/CODEC_TEMPLATE.js como ponto de partida.
// Exemplos: templates/codecs/example-thermal-sensor.js

function decodeUplink(input) {
  var bytes = input.bytes;
  if (bytes.length < 1) { return { data: {} }; }
  return { data: { raw: Array.from(bytes) } };
}
